  ('bookkeeper-moex-02070', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '某公司製品原料耗用數量，不符合營利事業所得稅查核準則第58條根據有關帳證紀錄予以核實認定之規 定，且財政部未定有通常水準，亦無同業原料耗用情形可資比照，則該公司原料耗用依序首先應按下列 何項核定？', '["按該公司上年度核定情形核定", "按該公司前五年度核定之平均數核定", "按該公司前三年度核定之平均數核定", "由稽徵機關調查核定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02071', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營利事業所得稅查核準則有關規定，下列敘述何者正確？', '["固定資產未達規定耐用年數而毀滅或廢棄者，全部應於事前報請稽徵機關核備，以其未折減餘額列為 該年度之損失", "帳列應付費用，逾二年尚未給付者，應該轉列其他收入", "開辦費之攤提，最低不得少於五年", "商品盤損之科目，僅係對於存貨採永續盤存制或經核准採零售價法者適用之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02072', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營利事業所得稅查核準則規定，營利事業之董事長、總經理、經理、廠長國內出差膳雜費，每人每日 之限額為多少元？', '["700元", "600元", "500元", "沒有金額限制"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02073', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營利事業所得稅查核準則規定，下列何項廣告費應報經稽徵機關核備，始准予以認列？', '["以車輛巡迴宣傳之各項費用", "樣品進口關稅與宣傳費等", "營建業樣品屋之成本", "參加義賣、特賣之各項費用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-02074', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依營利事業所得稅查核準則規定，已依職工福利金條例提撥福利金及經中央政府核准列支福利費用者， 其員工醫藥費應如何處理？', '["以薪資科目列報，計算限額", "以職工福利費科目列報，計算限額", "以職工福利費科目列報，核實認定", "不得列報"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
