  ('bookkeeper-moex-02076', 'bookkeeper', 'bookkeeper-moex-099-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '小規模營業人等以進項稅額百分之十扣減查定稅額者，依加值型及非加值型營業稅法及相關法規規定，其 進項憑證應分別於一、四、七、十月之幾日前，向主管稽徵機關申報並以當期各月份之進項憑證為限？', '["5日", "10日", "15日", "20日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:04+00:00", "source_pdf_sha1": "0086079d150f", "answer_pdf_sha1": "78f40e5694ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "602", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
